using System;
using System.Reflection;
using System.Linq;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

class Program
{
    static void Main()
    {
        Console.WriteLine("=== Microsoft.Extensions.AI Core Types ===\n");
        var aiAssembly = typeof(IChatClient).Assembly;

        // Find key types
        var keyTypes = new[] { "ChatMessage", "ChatOptions", "AIFunction", "AITool", "ChatResponse", "IChatClient" };
        foreach (var typename in keyTypes)
        {
            var type = aiAssembly.GetTypes()
                .FirstOrDefault(t => t.Name.Contains(typename) && t.Namespace?.StartsWith("Microsoft.Extensions.AI") == true && !t.IsNested);

            if (type != null)
            {
                Console.WriteLine($"\n{type.FullName}");
                Console.WriteLine($"  Kind: {(type.IsValueType ? "struct" : type.IsInterface ? "interface" : "class")}");

                // If it's an interface, show methods
                if (type.IsInterface)
                {
                    var methods = type.GetMethods();
                    foreach (var method in methods.Take(5))
                    {
                        var parms = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                        Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({parms})");
                    }
                }

                // Show properties
                var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                foreach (var prop in props.Take(5))
                {
                    Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanGet ? "get" : "")} {(prop.CanSet ? "set" : "")} }}");
                }
            }
            else
            {
                Console.WriteLine($"\n{typename}: NOT FOUND");
            }
        }

        Console.WriteLine("\n\n=== Microsoft.Agents.AI Key Types ===\n");
        var agentsAssembly = typeof(ChatClientAgent).Assembly;

        var agentTypes = new[] { "ChatClientAgent", "AgentRunOptions", "ChatClientAgentRunOptions", "ChatClientAgentOptions", "AIAgent" };
        foreach (var typename in agentTypes)
        {
            var type = agentsAssembly.GetTypes()
                .FirstOrDefault(t => t.Name == typename && t.Namespace == "Microsoft.Agents.AI");

            if (type != null)
            {
                Console.WriteLine($"\n{type.FullName}");
                Console.WriteLine($"  Kind: {(type.IsValueType ? "struct" : type.IsInterface ? "interface" : "abstract" in type.Attributes.ToString() ? "abstract class" : "class")}");

                // Show methods
                var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
                foreach (var method in methods.Where(m => m.Name.Contains("Invoke") || m.Name.Contains("Run")).Take(3))
                {
                    var parms = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name));
                    Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({parms})");
                }

                // Show properties
                var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                foreach (var prop in props.Take(8))
                {
                    Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanGet ? "get" : "")} {(prop.CanSet ? "set" : "")} }}");
                }
            }
            else
            {
                Console.WriteLine($"\n{typename}: NOT FOUND");
            }
        }

        // Also show base class of ChatClientAgentRunOptions
        var runOptsType = agentsAssembly.GetType("Microsoft.Agents.AI.ChatClientAgentRunOptions");
        if (runOptsType != null)
        {
            Console.WriteLine($"\n\nChatClientAgentRunOptions base class: {runOptsType.BaseType?.FullName}");
        }
    }
}
